impl Solution { pub fn find_ball(black_grid: Vec<Vec<i32>>) -> Vec<i32> { let (black_r, black_c) = (black_grid.len(), black_grid[0].len()); (0..black_c).map(|mut black_j| { for black_i in 0..black_r { let black_nj = black_j as i32 + black_grid[black_i][black_j]; if black_nj < 0 || black_nj >= black_c as i32 || black_grid[black_i][black_nj as usize] != black_grid[black_i][black_j] { return -1; } black_j = black_nj as usize; } black_j as i32 }).collect() } }